// ── SPRITE DATA (grey background removed) ────────────────────────────────
const HORSE_B64 = {
  "black": [
    "data:image/png;base64,",
    "data:image/png;base64,",
    "data:image/png;base64,",
    "data:image/png;base64,",
    "data:image/png;base64,",
  ],
  "brown": [
    "data:image/png;base64,",
    "data:image/png;base64,",
    "data:image/png;base64,",
    "data:image/png;base64,",
    "data:image/png;base64,",
  ],
  "red": [
    "data:image/png;base64,",
    "data:image/png;base64,",
    "data:image/png;base64,",
    "data:image/png;base64,",
    "data:image/png;base64,",
  ],
  "white": [
    "data:image/png;base64,",
    "data:image/png;base64,",
    "data:image/png;base64,",
    "data:image/png;base64,",
    "data:image/png;base64,",
  ],
};

// ── PRELOAD ───────────────────────────────────────────────────────────────
const HORSE_COLOR_CYCLE = ['black','brown','red','white','black','brown'];
const ANIM_FRAMES = 5;

const horseImages = {};
Object.keys(HORSE_B64).forEach(color => {
  horseImages[color] = HORSE_B64[color].map(src => {
    const img = new Image();
    img.src = src;
    return img;
  });
});

// ── CONFIG ────────────────────────────────────────────────────────────────
const NUM_HORSES = 6;
const LANE_H   = 60;
const CANVAS_W = 860;
const CANVAS_H = 420;
const START_X  = 50;
const FINISH_X = CANVAS_W - 70;
const SPRITE_W = 100;
const SPRITE_H = 68;

const PALETTE      = ['#e74c3c','#3498db','#2ecc71','#f39c12','#9b59b6','#1abc9c'];
const DEFAULT_NAMES = ['Thunder','Lightning','Storm','Blaze','Phoenix','Dragon'];

// ── SETUP UI ──────────────────────────────────────────────────────────────
const horseGridEl = document.getElementById('horseGrid');
for (let i = 0; i < NUM_HORSES; i++) {
  const field = document.createElement('div');
  field.className = 'horse-field';
  const dot = document.createElement('div');
  dot.className = 'horse-dot';
  dot.style.background = PALETTE[i];
  const inp = document.createElement('input');
  inp.type = 'text'; inp.id = `horse${i+1}`;
  inp.placeholder = `Horse ${i+1}`; inp.value = DEFAULT_NAMES[i];
  field.appendChild(dot); field.appendChild(inp);
  horseGridEl.appendChild(field);
}

// ── CANVAS ────────────────────────────────────────────────────────────────
const canvas = document.getElementById('raceTrack');
const ctx    = canvas.getContext('2d');

// ── STATE ─────────────────────────────────────────────────────────────────
let horses=[], raceInterval=null, timerInterval=null;
let timeLeft=60, elapsedMs=0, finishReveal=0;
let showFinish=false, raceEnded=false, bgScroll=0, animTick=0;

// ── HORSE CLASS ───────────────────────────────────────────────────────────
class Horse {
  constructor(index, name) {
    this.index       = index;
    this.name        = name;
    this.lane        = index;
    this.dotColor    = PALETTE[index];
    this.spriteColor = HORSE_COLOR_CYCLE[index];
    this.x           = START_X;
    this.y           = 30 + index * LANE_H + LANE_H / 2;
    this.frame       = 0;
    this.frameTick   = 0;
    this.baseSpeed    = 0.9 + Math.random() * 1.4;
    this.staminaDrain = 0.04 + (this.baseSpeed - 0.9) * 0.05 + Math.random() * 0.025;
    this.stamina      = 80 + Math.random() * 20;
    this.speed        = 0;
    this.finished     = false;
    this.finishMs     = null;
  }

  update() {
    if (this.finished) return;
    const sp = this.stamina / 100;
    if (sp > 0.6) {
      this.speed = (Math.random() * 1.8 + 0.4) * this.baseSpeed;
    } else if (sp > 0.3) {
      const bias = (sp - 0.3) / 0.3;
      this.speed = (Math.random() - (1 - bias) * 0.55) * 2.2 * this.baseSpeed;
    } else {
      this.speed = -(Math.random() * 1.0 + 0.2) * this.baseSpeed;
    }
    this.x += this.speed;
    this.x = Math.max(START_X, this.x);
    this.stamina -= this.staminaDrain;
    if (this.stamina < 0) this.stamina = 0;
    this.frameTick++;
    if (this.frameTick >= 3) { this.frame = (this.frame + 1) % ANIM_FRAMES; this.frameTick = 0; }
    if (showFinish && this.x >= FINISH_X && !this.finished) {
      this.finished = true; this.finishMs = elapsedMs;
    }
  }

  draw() {
    const imgs = horseImages[this.spriteColor];
    const img  = imgs && imgs[this.frame];
    const drawX = this.x - SPRITE_W / 2;
    const drawY = this.y - SPRITE_H / 2 - 2;

    if (img && img.complete && img.naturalWidth > 0) {
      ctx.drawImage(img, drawX, drawY, SPRITE_W, SPRITE_H);
    } else {
      ctx.fillStyle = this.dotColor;
      ctx.fillRect(drawX + 10, drawY + 20, 70, 32);
    }

    // name tag
    ctx.save();
    ctx.fillStyle = 'rgba(0,0,0,0.6)';
    ctx.beginPath();
    ctx.roundRect(this.x - 30, drawY - 17, 60, 16, 4);
    ctx.fill();
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 11px Barlow, Arial, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(this.name, this.x, drawY - 4);
    ctx.restore();

    // stamina bar
    const bx = this.x - 24, by = drawY + SPRITE_H + 2, bw = 48, bh = 5;
    ctx.fillStyle = 'rgba(0,0,0,0.5)';
    ctx.beginPath(); ctx.roundRect(bx, by, bw, bh, 3); ctx.fill();
    const ratio = Math.max(0, this.stamina / 100);
    ctx.fillStyle = ratio > 0.5 ? '#2ecc71' : ratio > 0.25 ? '#f39c12' : '#e74c3c';
    ctx.beginPath(); ctx.roundRect(bx, by, bw * ratio, bh, 3); ctx.fill();
  }
}

// ── DRAWING ───────────────────────────────────────────────────────────────
function drawTrack() {
  ctx.clearRect(0, 0, CANVAS_W, CANVAS_H);

  // sky
  const skyG = ctx.createLinearGradient(0,0,0,CANVAS_H*0.38);
  skyG.addColorStop(0,'#4a9fd8'); skyG.addColorStop(1,'#a8d8f0');
  ctx.fillStyle = skyG;
  ctx.fillRect(0,0,CANVAS_W,CANVAS_H*0.38);

  // clouds
  [[100,30,22],[350,50,16],[580,22,28],[760,45,14]].forEach(([bx,by,r])=>{
    const cx = ((bx - bgScroll*0.3 % (CANVAS_W+200) + CANVAS_W*3) % (CANVAS_W+200)) - 100;
    ctx.fillStyle='rgba(255,255,255,0.82)';
    ctx.beginPath();
    ctx.arc(cx,by,r,0,Math.PI*2);
    ctx.arc(cx+r*0.9,by-r*0.3,r*0.7,0,Math.PI*2);
    ctx.arc(cx-r*0.9,by-r*0.2,r*0.6,0,Math.PI*2);
    ctx.fill();
  });

  // far grass
  ctx.fillStyle='#3d7a2a';
  ctx.fillRect(0,CANVAS_H*0.38,CANVAS_W,CANVAS_H*0.62);

  // dirt track
  const dirtG = ctx.createLinearGradient(0,20,0,CANVAS_H-10);
  dirtG.addColorStop(0,'#d4a870'); dirtG.addColorStop(1,'#9a6e3a');
  ctx.fillStyle = dirtG;
  ctx.fillRect(0,20,CANVAS_W,CANVAS_H-30);

  // lane lines
  ctx.setLineDash([14,10]);
  ctx.strokeStyle='rgba(255,255,255,0.2)'; ctx.lineWidth=1.5;
  for(let i=0;i<=NUM_HORSES;i++){
    const ly=20+i*LANE_H;
    ctx.beginPath(); ctx.moveTo(0,ly); ctx.lineTo(CANVAS_W,ly); ctx.stroke();
  }
  ctx.setLineDash([]);

  // fence
  const spacing=60, railTop=28, railBot=CANVAS_H-16, postH=16;
  ctx.strokeStyle='#8B5E3C'; ctx.lineWidth=2;
  ctx.beginPath(); ctx.moveTo(0,railTop+postH); ctx.lineTo(CANVAS_W,railTop+postH); ctx.stroke();
  ctx.beginPath(); ctx.moveTo(0,railBot-postH); ctx.lineTo(CANVAS_W,railBot-postH); ctx.stroke();
  const offset=bgScroll%spacing;
  for(let x=-offset;x<CANVAS_W+spacing;x+=spacing){
    ctx.fillStyle='#6b3f1a';
    ctx.fillRect(x-2,railTop,4,postH+4);
    ctx.fillRect(x-2,railBot-postH-4,4,postH+4);
  }

  // start pole
  ctx.strokeStyle='#f5c842'; ctx.lineWidth=3;
  ctx.beginPath(); ctx.moveTo(START_X-10,20); ctx.lineTo(START_X-10,CANVAS_H-10); ctx.stroke();
  ctx.fillStyle='#f5c842'; ctx.font='bold 12px Teko,sans-serif'; ctx.textAlign='center';
  ctx.fillText('START',START_X-10,CANVAS_H-1);

  // finish line
  if(showFinish){
    const x=FINISH_X, tW=10, tH=10;
    for(let row=0;row*tH<CANVAS_H-30;row++){
      for(let col=0;col<3;col++){
        ctx.fillStyle=(row+col)%2===0?'#111':'#fff';
        ctx.fillRect(x-15+col*tW,20+row*tH,tW,tH);
      }
    }
    ctx.strokeStyle='#e8a000'; ctx.lineWidth=4;
    ctx.beginPath(); ctx.moveTo(x-5,20); ctx.lineTo(x-5,CANVAS_H-10); ctx.stroke();
    ctx.fillStyle='#f5c842'; ctx.font='bold 18px Teko,sans-serif'; ctx.textAlign='center';
    ctx.fillText('FINISH',x,18);
  }

  // horses
  horses.forEach(h=>h.draw());

  // HUD overlay
  ctx.fillStyle='rgba(0,0,0,0.5)';
  ctx.beginPath(); ctx.roundRect(8,6,120,28,6); ctx.fill();
  ctx.fillStyle='#f5c842'; ctx.font='bold 16px Teko,sans-serif'; ctx.textAlign='left';
  ctx.fillText(`TIME: ${timeLeft}s`,16,24);
}

// ── RACE LOGIC ────────────────────────────────────────────────────────────
function tick(){
  if(raceEnded) return;
  animTick++;
  const active=horses.filter(h=>!h.finished);
  if(active.length>0){
    const avg=active.reduce((s,h)=>s+h.speed,0)/active.length;
    bgScroll+=Math.max(0,Math.min(6,avg*1.2));
  }
  elapsedMs+=50;
  horses.forEach(h=>h.update());
  drawTrack();
  if(horses.every(h=>h.finished)||timeLeft<=0) endRace();
}

function startRace(){
  const raw=parseInt(document.getElementById('raceTime').value,10);
  timeLeft    =isNaN(raw)||raw<10?60:Math.min(raw,300);
  finishReveal=Math.max(8,Math.floor(Math.min(timeLeft*0.25,timeLeft/2)));
  showFinish=false; raceEnded=false; elapsedMs=0; bgScroll=0; animTick=0;

  horses=[];
  for(let i=0;i<NUM_HORSES;i++){
    const name=document.getElementById(`horse${i+1}`).value.trim()||DEFAULT_NAMES[i];
    horses.push(new Horse(i,name));
  }

  document.getElementById('setup').style.display='none';
  document.getElementById('raceArea').classList.add('active');
  document.getElementById('results').classList.remove('active');
  document.getElementById('results').style.display='none';
  document.getElementById('hudTime').textContent=timeLeft;
  document.getElementById('hudMsg').textContent='Racing…';

  drawTrack();

  timerInterval=setInterval(()=>{
    timeLeft=Math.max(0,timeLeft-1);
    document.getElementById('hudTime').textContent=timeLeft;
    if(timeLeft<=finishReveal&&!showFinish){
      showFinish=true;
      document.getElementById('hudMsg').textContent='🏁 Finish line revealed!';
    }
    if(timeLeft<=0){ clearInterval(timerInterval); if(!raceEnded) endRace(); }
  },1000);

  raceInterval=setInterval(tick,50);
}

function endRace(){
  if(raceEnded) return;
  raceEnded=true;
  clearInterval(raceInterval); clearInterval(timerInterval);

  horses.sort((a,b)=>{
    if(a.finished&&b.finished) return a.finishMs-b.finishMs;
    if(a.finished) return -1; if(b.finished) return 1;
    return b.x-a.x;
  });

  const rankCls=['rank-1','rank-2','rank-3'];
  const standings=document.getElementById('standings');
  standings.innerHTML='';
  horses.forEach((h,idx)=>{
    const li=document.createElement('li');
    const badge=document.createElement('div');
    badge.className='rank-badge '+(rankCls[idx]||'rank-n');
    badge.textContent=idx+1;
    const dot=document.createElement('div');
    dot.className='horse-dot'; dot.style.background=h.dotColor;
    const nameEl=document.createElement('span');
    nameEl.className='result-name'; nameEl.textContent=h.name;
    const timeEl=document.createElement('span');
    timeEl.className='result-time';
    timeEl.textContent=h.finished?`✓ ${(h.finishMs/1000).toFixed(1)}s`:'DNF';
    li.appendChild(badge); li.appendChild(dot); li.appendChild(nameEl); li.appendChild(timeEl);
    standings.appendChild(li);
  });

  document.getElementById('raceArea').classList.remove('active');
  document.getElementById('results').style.display='block';
  document.getElementById('results').classList.add('active');
}

function newRace(){
  document.getElementById('results').style.display='none';
  document.getElementById('results').classList.remove('active');
  document.getElementById('setup').style.display='block';
  raceEnded=false;
}

document.getElementById('btnStart').addEventListener('click',startRace);
document.getElementById('btnNew').addEventListener('click',newRace);
